```csharp
namespace Traxon.CryptoTrader.Domain.Common;

public sealed class Result<T>
{
    public T? Value { get; }
    public Error? Error { get; }
    public bool IsSuccess => Error is null;
    public bool IsFailure => !IsSuccess;

    private Result(T value)       { Value = value; Error = null; }
    private Result(Error error)   { Value = default; Error = error; }

    public static Result<T> Success(T value) => new(value);
    public static Result<T> Failure(Error error) => new(error);

    public TResult Match<TResult>(Func<T, TResult> onSuccess, Func<Error, TResult> onFailure) =>
        IsSuccess ? onSuccess(Value!) : onFailure(Error!);
}

public sealed record Error(string Code, string Message)
{
    public static readonly Error None = new(string.Empty, string.Empty);

    // Domain errors
    public static readonly Error NotEnoughCandles   = new("Domain.NotEnoughCandles",   "Buffer does not have enough candles for calculation.");
    public static readonly Error InvalidCandle       = new("Domain.InvalidCandle",       "Candle data is invalid.");
    public static readonly Error BufferFull          = new("Domain.BufferFull",          "Candle buffer is full.");
    public static readonly Error InvalidEdge         = new("Domain.InvalidEdge",         "Edge is below minimum threshold.");
    public static readonly Error PortfolioInsufficient = new("Domain.PortfolioInsufficient", "Insufficient balance.");
}
```

### 3.7 `Domain/Assets/Asset.cs`
```csharp
namespace Traxon.CryptoTrader.Domain.Assets;

public sealed class Asset : ValueObject
{
    public string Symbol { get; }         // "BTCUSDT"
    public string BaseAsset { get; }      // "BTC"
    public string QuoteAsset { get; }     // "USDT"

    private Asset(string symbol, string baseAsset, string quoteAsset)
    {
        Symbol = symbol;
        BaseAsset = baseAsset;
        QuoteAsset = quoteAsset;
    }

    // Predefined instances
    public static readonly Asset BTCUSDT  = new("BTCUSDT",  "BTC",  "USDT");
    public static readonly Asset ETHUSDT  = new("ETHUSDT",  "ETH",  "USDT");
    public static readonly Asset SOLUSDT  = new("SOLUSDT",  "SOL",  "USDT");
    public static readonly Asset XRPUSDT  = new("XRPUSDT",  "XRP",  "USDT");
    public static readonly Asset DOGEUSDT = new("DOGEUSDT", "DOGE", "USDT");
    public static readonly Asset HYPEUSDT = new("HYPEUSDT", "HYPE", "USDT");
    public static readonly Asset BNBUSDT  = new("BNBUSDT",  "BNB",  "USDT");

    public static readonly IReadOnlyList<Asset> All = [BTCUSDT, ETHUSDT, SOLUSDT, XRPUSDT, DOGEUSDT, HYPEUSDT, BNBUSDT];

    public static Asset? FromSymbol(string symbol) =>
        All.FirstOrDefault(a => a.Symbol.Equals(symbol, StringComparison.OrdinalIgnoreCase));

    protected override IEnumerable<object?> GetEqualityComponents() { yield return Symbol; }

    public override string ToString() => Symbol;
}
```

