### 5.4 `Binance/Adapters/BinanceMarketDataProvider.cs`

```csharp
using Binance.Net.Interfaces.Clients;
using Binance.Net.Enums;
using CryptoExchange.Net.Objects.Sockets;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;
using Traxon.CryptoTrader.Application.Abstractions;
using Traxon.CryptoTrader.Binance.Mappers;
using Traxon.CryptoTrader.Binance.Options;
using Traxon.CryptoTrader.Domain.Assets;
using Traxon.CryptoTrader.Domain.Market;

namespace Traxon.CryptoTrader.Binance.Adapters;

public sealed class BinanceMarketDataProvider : IMarketDataProvider, IAsyncDisposable
{
    private readonly IBinanceRestClient _restClient;
    private readonly IBinanceSocketClient _socketClient;
    private readonly ILogger<BinanceMarketDataProvider> _logger;
    private readonly BinanceOptions _options;

    private readonly List<UpdateSubscription> _subscriptions = [];
    private bool _isConnected;

    public bool IsConnected => _isConnected;

    public BinanceMarketDataProvider(
        IBinanceRestClient restClient,
        IBinanceSocketClient socketClient,
        ILogger<BinanceMarketDataProvider> logger,
        IOptions<BinanceOptions> options)
    {
        _restClient = restClient;
        _socketClient = socketClient;
        _logger = logger;
        _options = options.Value;
    }

    public async Task<IReadOnlyList<Candle>> GetHistoricalCandlesAsync(
        Asset asset,
        TimeFrame timeFrame,
        int limit,
        CancellationToken cancellationToken = default)
    {
        var interval = ToKlineInterval(timeFrame);

        var result = await _restClient.SpotApi.ExchangeData.GetKlinesAsync(
            symbol: asset.Symbol,
            interval: interval,
            limit: limit,
            ct: cancellationToken);

        if (!result.Success)
        {
            _logger.LogError("Binance REST klines failed for {Symbol}/{Interval}: {Error}",
                asset.Symbol, timeFrame.Value, result.Error?.Message);
            return [];
        }

        return result.Data
            .Select(k => BinanceMapper.ToCandle(k, asset, timeFrame))
            .OrderBy(c => c.OpenTime)
            .ToList()
            .AsReadOnly();
    }

    public async Task StartStreamAsync(
        IReadOnlyList<Asset> assets,
        IReadOnlyList<TimeFrame> timeFrames,
        Func<Candle, Task> onCandleClosed,
        CancellationToken cancellationToken = default)
    {
        // Build stream list: btcusdt@kline_5m, btcusdt@kline_15m, ...
        var streams = new List<(string symbol, KlineInterval interval, Asset asset, TimeFrame tf)>();

        foreach (var asset in assets)
        foreach (var tf in timeFrames)
            streams.Add((asset.Symbol.ToLowerInvariant(), ToKlineInterval(tf), asset, tf));

        _logger.LogInformation("Starting Binance WebSocket for {StreamCount} streams", streams.Count);

        foreach (var (symbol, interval, asset, tf) in streams)
        {
            var sub = await _socketClient.SpotApi.ExchangeStreams.SubscribeToKlineUpdatesAsync(
                symbol: symbol,
                interval: interval,
                onMessage: async data =>
                {
                    try
                    {
                        var candle = BinanceMapper.ToCandle(data.Data, asset, tf);

                        // Sadece kapanan candle'ları işle
                        if (candle.IsClosed)
                        {
                            _logger.LogDebug("Candle closed: {Symbol} {Interval} @ {CloseTime}",
                                asset.Symbol, tf.Value, candle.CloseTime);
                            await onCandleClosed(candle);
                        }
                    }
                    catch (Exception ex)
                    {
                        _logger.LogError(ex, "Error processing kline update for {Symbol}/{Interval}",
                            asset.Symbol, tf.Value);
                    }
                },
                ct: cancellationToken);

            if (sub.Success)
            {
                _subscriptions.Add(sub.Data);
                _logger.LogInformation("Subscribed: {Symbol}@kline_{Interval}", symbol, interval);
            }
            else
            {
                _logger.LogError("Failed to subscribe: {Symbol}@kline_{Interval} — {Error}",
                    symbol, interval, sub.Error?.Message);
            }
        }

        _isConnected = _subscriptions.Count > 0;
    }

    public async Task StopStreamAsync(CancellationToken cancellationToken = default)
    {
        foreach (var sub in _subscriptions)
            await sub.CloseAsync();

        _subscriptions.Clear();
        _isConnected = false;
        _logger.LogInformation("Binance WebSocket streams stopped");
    }

    private static KlineInterval ToKlineInterval(TimeFrame tf) => tf.Value switch
    {
        "5m"  => KlineInterval.FiveMinutes,
        "15m" => KlineInterval.FifteenMinutes,
        _     => throw new ArgumentOutOfRangeException(nameof(tf), $"Unsupported timeframe: {tf.Value}")
    };

    public async ValueTask DisposeAsync()
    {
        await StopStreamAsync();
        _restClient.Dispose();
        _socketClient.Dispose();
    }
}
```

### 5.5 `Binance/Buffers/InMemoryCandleBuffer.cs`

```csharp
using System.Collections.Concurrent;
using Traxon.CryptoTrader.Application.Abstractions;
using Traxon.CryptoTrader.Domain.Assets;
using Traxon.CryptoTrader.Domain.Common;
using Traxon.CryptoTrader.Domain.Market;

namespace Traxon.CryptoTrader.Binance.Buffers;

public sealed class InMemoryCandleBuffer : ICandleBuffer
{
    private readonly ConcurrentDictionary<string, LinkedList<Candle>> _buffers = new();
    private readonly object _lock = new();

    public int Capacity { get; }

    public InMemoryCandleBuffer(int capacity = 200) => Capacity = capacity;

    private static string Key(Asset asset, TimeFrame timeFrame) =>
        $"{asset.Symbol}:{timeFrame.Value}";

    public void Add(Candle candle)
    {
        var key = Key(candle.Asset, candle.TimeFrame);
        var list = _buffers.GetOrAdd(key, _ => new LinkedList<Candle>());

        lock (_lock)
        {
            // Aynı OpenTime varsa güncelle (partial candle update)
            var existing = list.FirstOrDefault(c => c.OpenTime == candle.OpenTime);
            if (existing is not null)
            {
                list.Remove(existing);
            }

            list.AddLast(candle);

            // Rolling window: Capacity aşılırsa en eskiyi sil
            while (list.Count > Capacity)
                list.RemoveFirst();
        }
    }

    public Result<IReadOnlyList<Candle>> GetLast(Asset asset, TimeFrame timeFrame, int count)
    {
        var key = Key(asset, timeFrame);
        if (!_buffers.TryGetValue(key, out var list) || list.Count < count)
            return Result<IReadOnlyList<Candle>>.Failure(Error.NotEnoughCandles);

        lock (_lock)
        {
            var result = list.TakeLast(count).ToList().AsReadOnly();
            return Result<IReadOnlyList<Candle>>.Success(result);
        }
    }

    public Result<IReadOnlyList<Candle>> GetAll(Asset asset, TimeFrame timeFrame)
    {
        var key = Key(asset, timeFrame);
        if (!_buffers.TryGetValue(key, out var list) || list.Count == 0)
            return Result<IReadOnlyList<Candle>>.Failure(Error.NotEnoughCandles);

        lock (_lock)
        {
            return Result<IReadOnlyList<Candle>>.Success(list.ToList().AsReadOnly());
        }
    }

    public int Count(Asset asset, TimeFrame timeFrame)
    {
        var key = Key(asset, timeFrame);
        return _buffers.TryGetValue(key, out var list) ? list.Count : 0;
    }

    public bool IsWarmedUp(Asset asset, TimeFrame timeFrame, int minimumCandles = 50) =>
        Count(asset, timeFrame) >= minimumCandles;
}
